amends "package://github.com/jdx/hk/releases/download/v1.36.0/hk@1.36.0#/Config.pkl"
import "package://github.com/jdx/hk/releases/download/v1.36.0/hk@1.36.0#/Builtins.pkl"

local base_steps = new Mapping<String, Step> {
    ["trailing_whitespace"] = Builtins.trailing_whitespace
    ["newlines"] = Builtins.newlines
    ["check_merge_conflict"] = Builtins.check_merge_conflict
    ["detect_private_key"] = Builtins.detect_private_key
    ["check_added_large_files"] = Builtins.check_added_large_files
    ["check_symlinks"] = Builtins.check_symlinks
    ["check_executables_have_shebangs"] = Builtins.check_executables_have_shebangs
}

local python_steps = new Mapping<String, Step> {
    ["ruff"] = Builtins.ruff
    ["ruff_format"] = Builtins.ruff_format
    ["shellcheck"] = Builtins.shellcheck
    ["python_check_ast"] = Builtins.python_check_ast
}

local validation_steps = new Mapping<String, Step> {
    ["check_yaml"] {
        glob = "**/*.{yml,yaml}"
        exclude = Regex(#"(examples/.*\.yaml$|specs/.*\.yaml$)"#)
        check = "python -c \"import yaml, sys; [yaml.safe_load(open(f)) for f in sys.argv[1:]]\""
    }
    ["check_json"] {
        glob = "**/*.json"
        check = "python -c \"import json, sys; [json.load(open(f)) for f in sys.argv[1:]]\""
    }
}

local manual_steps = new Mapping<String, Step> {
    ["rumdl"] {
        glob = "{README.md,plugins/*/README.md,plugins/*/*/README.md,docs/architecture/*.md}"
        check = "rumdl"
    }
}

local commit_steps = new Mapping<String, Step> {
    ["check_conventional_commit"] = Builtins.check_conventional_commit
}

hooks {
    ["pre-commit"] {
        fix = true
        stash = "git"
        steps {
            ...base_steps
            ...python_steps
            ...validation_steps
        }
    }
    ["commit-msg"] {
        steps = commit_steps
    }
    ["check"] {
        steps {
            ...base_steps
            ...python_steps
            ...validation_steps
            ...manual_steps
        }
    }
    ["fix"] {
        fix = true
        steps {
            ...base_steps
            ...python_steps
            ...validation_steps
            ...manual_steps
        }
    }
}

